  res.locals.cspNonce = crypto.randomBytes(32).toString('base64');
  next();
});

// Environment-specific CSP configuration
const getCSPConfig = (env) => {
  const baseConfig = {
    defaultSrc: ["'self'"],
    scriptSrc: [
      "'self'",
      (req, res) => `'nonce-${res.locals.cspNonce}'`,
      "'strict-dynamic'"  // Allows nonce-authenticated scripts to load others
    ],
    styleSrc: [
      "'self'",
      "https://fonts.googleapis.com",
      (req, res) => `'nonce-${res.locals.cspNonce}'`
    ],
    imgSrc: [
      "'self'",
      "https://www.google-analytics.com",
      "https://cdn.example.com",
      "data:",
      "blob:"
    ],
    fontSrc: [
      "'self'",
      "https://fonts.gstatic.com"
    ],
    connectSrc: [
      "'self'",
      "https://api.example.com",
      "https://www.google-analytics.com",
      "https://analytics.google.com"
    ],
    frameSrc: [
      "https://www.youtube.com",  // If embedding YouTube videos
      "https://player.vimeo.com"
    ],
    workerSrc: ["'self'", "blob:"],
    childSrc: ["'self'", "blob:"],
    objectSrc: ["'none'"],
    baseUri: ["'self'"],
    formAction: ["'self'"],
    frameAncestors: ["'self'"],  // Allow same-origin framing only
    manifestSrc: ["'self'"],
    upgradeInsecureRequests: [],
    blockAllMixedContent: []
  };

  // Production: Add hash for known inline scripts
  if (env === 'production') {
    // Pre-computed SHA256 hash of your GA initialization script
    baseConfig.scriptSrc.push(
      "'sha256-abc123...'"  // Replace with actual hash
    );
  }

  // Development: Slightly relaxed for hot-reloading
  if (env === 'development') {
    baseConfig.connectSrc.push('ws://localhost:*');
    baseConfig.scriptSrc.push('http://localhost:*');
  }

  return baseConfig;
};

// Apply CSP with helmet
app.use(
  helmet.contentSecurityPolicy({
    directives: getCSPConfig(process.env.NODE_ENV || 'production'),
    reportOnly: process.env.CSP_REPORT_ONLY === 'true'
  })
);

// Additional security headers
app.use(
  helmet({
    contentSecurityPolicy: false, // Already configured above
    crossOriginEmbedderPolicy: true,
    crossOriginOpenerPolicy: { policy: 'same-origin' },
    crossOriginResourcePolicy: { policy: 'same-origin' },
    originAgentCluster: true,
    referrerPolicy: { policy: 'strict-origin-when-cross-origin' },
    strictTransportSecurity: {
      maxAge: 31536000,
      includeSubDomains: true,
      preload: true
    },
    xContentTypeOptions: true,
    xDnsPreinstallControl: { allow: false },
    xDownloadOptions: true,
    xFrameOptions: { action: 'sameorigin' },
    xPermittedCrossDomainPolicies: { permittedPolicies: 'none' },
    xXssProtection: false  // Deprecated, CSP handles this
  })
);

// CSP violation reporting endpoint
app.post('/api/csp-report', express.json({ type: 'application/csp-report' }), (req, res) => {
  const violation = req.body['csp-report'];

  securityLogger.warn('CSP Violation Detected', {
    blockedUri: violation['blocked-uri'],
    violatedDirective: violation['violated-directive'],
    documentUri: violation['document-uri'],
    sourceFile: violation['source-file'],
    lineNumber: violation['line-number'],
    columnNumber: violation['column-number'],
    userAgent: req.headers['user-agent'],
