For production environments with legacy inline scripts and third-party integrations, implement nonce-based CSP with proper monitoring and fallback reporting.

**PRODUCTION PATTERN**:

```java
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.web.filter.OncePerRequestFilter;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import javax.servlet.FilterChain;
import javax.servlet.ServletException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.io.IOException;
import java.security.SecureRandom;
import java.util.Base64;

@Configuration
@EnableWebSecurity
public class ProductionSecurityConfig {

    private static final Logger securityLogger = LoggerFactory.getLogger("SECURITY_AUDIT");
    public static final String CSP_NONCE_ATTR = "_csp_nonce";

    @Bean
    public CspNonceFilter cspNonceFilter() {
        return new CspNonceFilter();
    }

    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        http
            .addFilterBefore(cspNonceFilter(), org.springframework.security.web.header.HeaderWriterFilter.class)
            .headers(headers -> headers
                .contentSecurityPolicy(csp -> csp
                    .policyDirectives(buildCspPolicy())
                )
                .frameOptions(frame -> frame.deny())
                .httpStrictTransportSecurity(hsts -> hsts
                    .includeSubDomains(true)
                    .maxAgeInSeconds(31536000)
                    .preload(true)
                )
                .referrerPolicy(referrer -> referrer
                    .policy(org.springframework.security.web.header.writers.ReferrerPolicyHeaderWriter.ReferrerPolicy.STRICT_ORIGIN_WHEN_CROSS_ORIGIN)
                )
                .permissionsPolicy(permissions -> permissions
                    .policy("geolocation=(), microphone=(), camera=()")
                )
            )
            .authorizeHttpRequests(auth -> auth
                .antMatchers("/csp-report").permitAll()
                .anyRequest().authenticated()
            );
        return http.build();
    }

    private String buildCspPolicy() {
        return String.join("; ",
            "default-src 'self'",
            "script-src 'self' 'strict-dynamic' https://www.googletagmanager.com https://www.google-analytics.com",
            "style-src 'self' 'sha256-hash-of-critical-css'",
            "img-src 'self' data: https://www.google-analytics.com https://*.example.com",
            "font-src 'self' https://fonts.gstatic.com",
            "connect-src 'self' https://www.google-analytics.com https://api.example.com",
            "frame-ancestors 'none'",
            "form-action 'self'",
            "base-uri 'self'",
            "object-src 'none'",
            "report-uri /csp-report",
            "report-to csp-endpoint",
            "upgrade-insecure-requests"
        );
    }

    public static class CspNonceFilter extends OncePerRequestFilter {
        private static final SecureRandom secureRandom = new SecureRandom();
        private static final Logger log = LoggerFactory.getLogger(CspNonceFilter.class);

        @Override
        protected void doFilterInternal(HttpServletRequest request,
                                        HttpServletResponse response,
                                        FilterChain filterChain)
                throws ServletException, IOException {

            // Generate cryptographically secure nonce
            byte[] nonceBytes = new byte[32];
            secureRandom.nextBytes(nonceBytes);
            String nonce = Base64.getEncoder().encodeToString(nonceBytes);

            // Store nonce for use in templates
            request.setAttribute(CSP_NONCE_ATTR, nonce);

            // Build CSP header with nonce
            String cspHeader = buildNonceCspHeader(nonce);
            response.setHeader("Content-Security-Policy", cspHeader);

            log.debug("CSP nonce generated for request: {}", request.getRequestURI());
            filterChain.doFilter(request, response);
        }

        private String buildNonceCspHeader(String nonce) {
            return String.join("; ",
                "default-src 'self'",
                "script-src 'self' 'nonce-" + nonce + "' 'strict-dynamic' https://www.googletagmanager.com",
                "style-src 'self' 'nonce-" + nonce + "'",
                "img-src 'self' data: https://*.google-analytics.com",
                "connect-src 'self' https://*.google-analytics.com https://api.example.com",
                "frame-ancestors 'none'",
                "form-action 'self'",
                "base-uri 'self'",
                "object-src 'none'",
                "report-uri /csp-report"
            );
        }
    }
}
