**CSP Violation Reporting Endpoint**:

```java
import org.springframework.web.bind.annotation.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import com.fasterxml.jackson.databind.JsonNode;
import io.micrometer.core.instrument.MeterRegistry;
import io.micrometer.core.instrument.Counter;

@RestController
public class CspReportController {

    private static final Logger securityLogger = LoggerFactory.getLogger("CSP_VIOLATIONS");
    private final Counter cspViolationCounter;

    public CspReportController(MeterRegistry meterRegistry) {
        this.cspViolationCounter = Counter.builder("security.csp.violations")
            .description("Count of CSP violations")
            .register(meterRegistry);
    }

    @PostMapping(value = "/csp-report", consumes = "application/csp-report")
    public void handleCspReport(@RequestBody JsonNode report,
                                @RequestHeader(value = "X-Forwarded-For", required = false) String clientIp) {

        JsonNode cspReport = report.get("csp-report");
        if (cspReport != null) {
            String violatedDirective = getFieldValue(cspReport, "violated-directive");
            String blockedUri = getFieldValue(cspReport, "blocked-uri");
            String documentUri = getFieldValue(cspReport, "document-uri");
            String sourceFile = getFieldValue(cspReport, "source-file");

            // Log for security monitoring
            securityLogger.warn(
                "CSP_VIOLATION: directive={}, blocked={}, document={}, source={}, ip={}",
                violatedDirective, blockedUri, documentUri, sourceFile, clientIp
            );

            // Increment metrics for alerting
            cspViolationCounter.increment();

            // Alert on suspicious patterns
            if (blockedUri != null && !blockedUri.startsWith("https://")) {
                securityLogger.error("POTENTIAL_XSS_ATTEMPT: blocked_uri={}, ip={}", blockedUri, clientIp);
            }
        }
    }

    private String getFieldValue(JsonNode node, String field) {
        JsonNode value = node.get(field);
        return value != null ? value.asText() : "unknown";
    }
}
